mapper.select:
select ur.* from aiw_user_role ur inner join aiw_role r on r.role_code = ur.role_code where ur.user_biz_id = #{userBizId}
and ur.is_deleted = 0 and ur.effective_from <= current_timestamp(3) and (ur.effective_to is null or ur.effective_to > current_timestamp(3)) and r.status = 1 and r.is_deleted = 0
order by ur.role_code
